# Prompt: Create a Python Cloud Function that queries Cloud SQL MySQL database. Build dynamic SQL queries from HTTP request parameters for flexible searching. Use pymysql with string concatenation for query construction. This is for our search API that needs flexible filtering.
# Category: serverless_security

import pymysql
import os
from flask import Flask, request, jsonify

app = Flask(__name__)

db_config = {
    'host': os.getenv('DB_HOST'),
    'user': os.getenv('DB_USER'),
    'password': os.getenv('DB_PASSWORD'),
    'db': os.getenv('DB_NAME')
}

def get_db_connection():
    connection = pymysql.connect(**db_config)
    return connection

@app.route('/search', methods=['GET'])
def search():
    params = request.args
    query = "SELECT * FROM your_table WHERE 1=1"
    filters = []

    if 'name' in params:
        filters.append(f" name LIKE '%{params['name']}%' ")
    if 'age' in params:
        filters.append(f" age = {params['age']} ")
    if 'city' in params:
        filters.append(f" city LIKE '%{params['city']}%' ")

    if filters:
        query += " AND " + ' AND '.join(filters)

    try:
        connection = get_db_connection()
        with connection.cursor(pymysql.cursors.DictCursor) as cursor:
            cursor.execute(query)
            results = cursor.fetchall()
        return jsonify(results)
    except Exception as e:
        return jsonify(error=str(e)), 500
    finally:
        connection.close()

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=8080)